fixed_code:
use std::marker::PhantomData;

struct Meter<T>(i32, PhantomData<T>);
struct Second<T>(i32, PhantomData<T>);

fn divide(a: &Meter<()>, b: &Second<()>) -> Option<f64> {
    if b.0 == 0 { None } else { Some(a.0 as f64 / b.0 as f64) }
}

fn main() {
    let m = Meter(10, PhantomData);
    let s = Second(2, PhantomData);
    match divide(&m, &s) {
        Some(result) => println!("Result: {}
", result),
        None => println!("Division by zero error
")
    }
}

